<template>
  <div>
    <el-button type="primary" @click="load">刷新</el-button>
    <el-table :data="list" style="width:100%;margin-top:12px">
      <el-table-column prop="username" label="用户名" />
      <el-table-column prop="email" label="邮箱" />
      <el-table-column prop="role" label="角色" />
      <el-table-column label="操作" width="200">
        <template #default="{row}">
          <el-select v-model="row.role" style="width:140px" @change="updateRole(row)">
            <el-option label="学生" value="ROLE_STUDENT" />
            <el-option label="管理员" value="ROLE_ADMIN" />
            <el-option label="负责人" value="ROLE_MANAGER" />
          </el-select>
          <el-button size="small" type="danger" @click="remove(row)">删除</el-button>
        </template>
      </el-table-column>
    </el-table>
  </div>
</template>
<script setup lang="ts">
import { ref } from 'vue'
import http from '../api/http'
const list = ref<any[]>([])
async function load() {
  const { data } = await http.get('/user/list')
  list.value = data
}
async function updateRole(row:any) { await http.put('/user/update', { id: row.id, role: row.role }) }
async function remove(row:any) { await http.delete('/user/delete', { data: { id: row.id } }); load() }
load()
</script>
